//! Fluent-based i18n for log messages and RPC replies.
//!
//! FTL lang files are bundled at compile time via `build.rs` (`BUNDLED_LANGS`).
//! A compiled-in `i18n_cid` from `src/i18n.yaml` (generated by `make src/i18n.yaml`)
//! is used as the default IPFS lang-map pointer; `config.extra["i18n_cid"]` overrides it.
//! Call [`init`] once after Kubo is ready.

use std::collections::HashMap;
use std::sync::{OnceLock, RwLock};

use fluent::{FluentBundle, FluentResource};
use unic_langid::LanguageIdentifier;

use crate::entity::{IpldLink, RuntimeManifest};
use crate::kubo;

/// All messages keyed by `(lang_code, message_id)`. Wrapped in `RwLock` so
/// the runtime language can be switched at any time without restart.
static MESSAGES: OnceLock<RwLock<HashMap<String, HashMap<String, String>>>> = OnceLock::new();
static RUNTIME_LANG: OnceLock<RwLock<String>> = OnceLock::new();

// `BUNDLED_LANGS` is auto-generated by build.rs from all `lang/*.ftl` files.
// Drop a new FTL file and rebuild — it is included automatically.
include!(concat!(env!("OUT_DIR"), "/bundled_langs.rs"));

/// Compiled-in `src/i18n.yaml` — generated by `make src/i18n.yaml`.
/// Contains `i18n_cid` (the IPFS DAG-CBOR map CID) and per-language CIDs.
const LANG_YAML: &str = include_str!("i18n.yaml");

/// Returns the compiled-in fallback lang-map CID from `src/i18n.yaml`.
/// `None` when `make src/i18n.yaml` has never been run.
pub fn default_lang_cid() -> Option<&'static str> {
    static CID: OnceLock<Option<String>> = OnceLock::new();
    CID.get_or_init(|| {
        let v: serde_yaml::Value = serde_yaml::from_str(LANG_YAML).ok()?;
        v.get("i18n_cid")?.as_str().map(String::from)
    })
    .as_deref()
}

/// Per-language CIDs from the compiled-in `src/i18n.yaml`.
/// Returns an empty map when `make src/i18n.yaml` has never been run.
pub fn bundled_lang_map() -> HashMap<String, IpldLink> {
    let v: serde_yaml::Value = serde_yaml::from_str(LANG_YAML).unwrap_or_default();
    let langs = v
        .get("langs")
        .and_then(|l| l.as_mapping())
        .cloned()
        .unwrap_or_default();
    langs
        .into_iter()
        .filter_map(|(k, v)| {
            k.as_str()
                .zip(v.as_str())
                .map(|(k, cid)| (k.to_string(), IpldLink::new(cid)))
        })
        .collect()
}

