/// Initialise i18n by loading all compiled-in FTL bundles and fetching any
/// additional ones from IPFS. `lang` is the runtime's own language.
///
/// On first call the `RwLock` statics are created. On subsequent calls
/// messages and the active language are updated through the write locks, so
/// the runtime is immediately re-localised without restarting.
pub async fn init(lang: &str, kubo_url: &str, lang_cid: Option<&str>, root_cid: Option<&str>) {
    let messages = load_all_messages(kubo_url, lang_cid, root_cid).await;
    if MESSAGES.set(RwLock::new(messages.clone())).is_err() {
        if let Some(lock) = MESSAGES.get() {
            *lock.write().expect("MESSAGES poisoned") = messages;
        }
    }
    if RUNTIME_LANG.set(RwLock::new(lang.to_string())).is_err() {
        if let Some(lock) = RUNTIME_LANG.get() {
            *lock.write().expect("RUNTIME_LANG poisoned") = lang.to_string();
        }
    }
}

/// Return the localised string for `id` in the runtime's own language.
/// Falls back to `id` itself when [`init`] has not been called or the key is
/// unknown — so callers always get *something* human-readable.
#[must_use]
pub fn t(id: &str) -> String {
    let lang = runtime_lang();
    t_lang(&lang, id)
}

/// Like [`t_lang`] but substitutes `%name%` placeholders in the translated
/// string with caller-supplied values.  Placeholders use `%name%` syntax
/// (not Fluent `{ $name }`) so the FTL values remain plain text.
#[must_use]
pub fn tf_lang(lang: &str, id: &str, args: &[(&str, &str)]) -> String {
    let mut s = t_lang(lang, id);
    for (name, value) in args {
        s = s.replace(&format!("%{name}%"), value);
    }
    s
}

/// Return the localised string for `id` in `lang`.
/// Falls back to "en" if `lang` is not loaded, then to the key name.
#[must_use]
pub fn t_lang(lang: &str, id: &str) -> String {
    let Some(lock) = MESSAGES.get() else {
        return id.to_string();
    };
    let Ok(all) = lock.read() else {
        return id.to_string();
    };
    all.get(lang)
        .or_else(|| all.get("en"))
        .and_then(|m| m.get(id))
        .cloned()
        .unwrap_or_else(|| id.to_string())
}

/// The runtime's own language code (set by [`init`]; defaults to "en").
#[must_use]
pub fn runtime_lang() -> String {
    RUNTIME_LANG
        .get()
        .and_then(|lock| lock.read().ok().map(|g| g.clone()))
        .unwrap_or_else(|| "en".to_string())
}

/// Returns `true` if messages for `lang` have been loaded.
#[must_use]
pub fn has_lang(lang: &str) -> bool {
    MESSAGES
        .get()
        .and_then(|lock| lock.read().ok().map(|all| all.contains_key(lang)))
        .unwrap_or(false)
}

/// Switch the runtime language immediately without restarting.
///
/// Tries the compiled-in FTL bundle first (no network needed). Falls back to
/// fetching the raw FTL blob from IPFS via the CID in `src/i18n.yaml`.
/// No-op when the language is unknown and unreachable from IPFS.
pub async fn switch_lang(lang: &str, kubo_url: &str) {
    let messages = if let Some((_, ftl)) = BUNDLED_LANGS.iter().find(|(code, _)| *code == lang) {
        parse_ftl(ftl, lang)
    } else {
        let lang_map = bundled_lang_map();
        let Some(link) = lang_map.get(lang) else {
            return;
        };
        let Ok(bytes) = ma_core::cat_bytes(kubo_url, &link.cid).await else {
            return;
        };
        let Ok(ftl) = String::from_utf8(bytes) else {
            return;
        };
        parse_ftl(&ftl, lang)
    };
    if let Some(lock) = MESSAGES.get() {
        lock.write()
            .expect("MESSAGES poisoned")
            .insert(lang.to_string(), messages);
    }
    if let Some(lock) = RUNTIME_LANG.get() {
        *lock.write().expect("RUNTIME_LANG poisoned") = lang.to_string();
    }
}

// ── Internals ─────────────────────────────────────────────────────────────────

fn parse_ftl(ftl: &str, lang: &str) -> HashMap<String, String> {
    let Ok(resource) = FluentResource::try_new(ftl.to_string()) else {
        return key_name_fallback();
    };
    let langid: LanguageIdentifier = lang
        .parse()
        .unwrap_or_else(|_| "en".parse().expect("invalid fallback lang"));
    let mut bundle: FluentBundle<FluentResource> = FluentBundle::new(vec![langid]);
    if bundle.add_resource(resource).is_err() {
        return key_name_fallback();
    }

    let mut map = HashMap::new();
    for &id in MESSAGE_IDS {
        if let Some(msg) = bundle.get_message(id) {
            if let Some(pattern) = msg.value() {
                let mut errors = vec![];
                let value = bundle.format_pattern(pattern, None, &mut errors);
                map.insert(id.to_string(), value.into_owned());
            } else {
                map.insert(id.to_string(), id.to_string());
            }
        } else {
            map.insert(id.to_string(), id.to_string());
        }
    }
    map
}

fn key_name_fallback() -> HashMap<String, String> {
    MESSAGE_IDS
        .iter()
        .map(|&id| (id.to_string(), id.to_string()))
        .collect()
}

fn bundled_messages() -> HashMap<String, HashMap<String, String>> {
    BUNDLED_LANGS
        .iter()
        .map(|&(code, ftl)| (code.to_string(), parse_ftl(ftl, code)))
        .collect()
}

async fn fetch_lang_map(
    kubo_url: &str,
    lang_cid: Option<&str>,
    root_cid: Option<&str>,
) -> HashMap<String, IpldLink> {
    if let Some(cid) = lang_cid {
        if let Ok(map) = kubo::dag_get(kubo_url, cid).await {
            return map;
        }
    }
    if let Some(cid) = root_cid {
        if let Ok(manifest) = kubo::dag_get::<RuntimeManifest>(kubo_url, cid).await {
            return manifest.i18n;
        }
    }
    HashMap::new()
}

/// Resolve the active language code from `manifest.config["i18n"]`.
/// Returns `None` when the manifest is unreachable or the key is absent.
pub async fn resolve_active_lang(kubo_url: &str, root_cid: &str) -> Option<String> {
    let manifest: RuntimeManifest = kubo::dag_get(kubo_url, root_cid).await.ok()?;
    manifest
        .config
        .get("i18n")
        .and_then(|v| v.as_str())
        .map(String::from)
}

async fn load_all_messages(
    kubo_url: &str,
    lang_cid: Option<&str>,
    root_cid: Option<&str>,
) -> HashMap<String, HashMap<String, String>> {
    let mut all = bundled_messages();

    let lang_map = fetch_lang_map(kubo_url, lang_cid, root_cid).await;
    for (code, link) in &lang_map {
        if let Ok(bytes) = ma_core::cat_bytes(kubo_url, &link.cid).await {
            if let Ok(ftl) = String::from_utf8(bytes) {
                all.insert(code.clone(), parse_ftl(&ftl, code));
            }
        }
    }

    all
}
